use strict;
use warnings;

sub delete_files {
    my $dir = shift;
    my $files = glob("$dir/*");
    foreach my $file (@$files) {
        if (-f $file) {
            unlink $file;
        } elsif (-d $file) {
            delete_files($file);
        }
    }
}

